namespace sv_c4beb1b25b3c466b89242fc95770ed27.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public record NewTaskModel(string Title, string Assignee, string Priority, DateTime DueDate);

namespace sv_c4beb1b25b3c466b89242fc95770ed27.Services;

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@using sv_c4beb1b25b3c466b89242fc95770ed27.Services

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1">
            <small class="text-muted">@Task.Assignee</small>
        </p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div class="mt-2">
            @if (CanMoveLeft)
            {
                <button class="btn btn-sm btn-outline-secondary me-1"
                        @onclick="@(() => OnMoveLeft.InvokeAsync(Task.Id))">
                    &larr; Move Left
                </button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-sm btn-outline-secondary"
                        @onclick="@(() => OnMoveRight.InvokeAsync(Task.Id))">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@using sv_c4beb1b25b3c466b89242fc95770ed27.Services

<div class="card mt-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm"
                   placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm"
                   placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <button class="btn btn-sm btn-primary me-1" @onclick="Save">Save</button>
        <button class="btn btn-sm btn-secondary" @onclick="Cancel">Cancel</button>
    </div>
</div>

@code {
    [Parameter] public EventCallback<NewTaskModel> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title)) return;
        await OnSave.InvokeAsync(new NewTaskModel(title, assignee, priority, dueDate));
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }

    private async Task Cancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@using sv_c4beb1b25b3c466b89242fc95770ed27.Services

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@Title</h5>
            <span class="badge bg-primary rounded-pill">@Tasks.Count</span>
        </div>
        <div class="card-body" style="min-height: 200px;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="OnMoveLeft"
                          OnMoveRight="OnMoveRight" />
            }

            @if (showAddForm)
            {
                <AddTaskForm OnSave="HandleSave"
                             OnCancel="@(() => showAddForm = false)" />
            }
            else
            {
                <button class="btn btn-sm btn-outline-primary w-100 mt-2"
                        @onclick="@(() => showAddForm = true)">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Title { get; set; } = "";
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public EventCallback<NewTaskModel> OnAddTask { get; set; }

    private bool showAddForm;

    private async Task HandleSave(NewTaskModel model)
    {
        await OnAddTask.InvokeAsync(model);
        showAddForm = false;
    }
}

@using sv_c4beb1b25b3c466b89242fc95770ed27.Services

<div class="d-flex gap-2 flex-wrap mb-3">
    <span class="badge bg-secondary fs-6">Total: @Tasks.Count</span>
    <span class="badge bg-info text-dark fs-6">To Do: @Tasks.Count(t => t.Status == "To Do")</span>
    <span class="badge bg-primary fs-6">In Progress: @Tasks.Count(t => t.Status == "In Progress")</span>
    <span class="badge bg-success fs-6">Done: @Tasks.Count(t => t.Status == "Done")</span>
    <span class="badge bg-danger fs-6">Overdue: @OverdueCount</span>
</div>

@code {
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();

    private int OverdueCount => Tasks.Count(t => t.DueDate < DateTime.Today);
}

@page "/board"
@using sv_c4beb1b25b3c466b89242fc95770ed27.Services
@using sv_c4beb1b25b3c466b89242fc95770ed27.Components.Board
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">@errorMessage</div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn Title="To Do"
                     Tasks="@(GetTasksForStatus("To Do"))"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveRight="@(id => MoveTask(id, "In Progress"))"
                     OnAddTask="@(model => AddTask(model, "To Do"))" />

        <BoardColumn Title="In Progress"
                     Tasks="@(GetTasksForStatus("In Progress"))"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveLeft="@(id => MoveTask(id, "To Do"))"
                     OnMoveRight="@(id => MoveTask(id, "Done"))"
                     OnAddTask="@(model => AddTask(model, "In Progress"))" />

        <BoardColumn Title="Done"
                     Tasks="@(GetTasksForStatus("Done"))"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveLeft="@(id => MoveTask(id, "In Progress"))"
                     OnAddTask="@(model => AddTask(model, "Done"))" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetTasksForStatus(string status)
    {
        var filtered = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t =>
                t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var index = allTasks.FindIndex(t => t.Id == taskId);
            if (index >= 0)
            {
                allTasks[index] = allTasks[index] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask(NewTaskModel model, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(
                model.Title, model.Assignee, model.Priority, model.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

