toolArgs.file_text:
@page "/board"
@using sv_c4beb1b25b3c466b89242fc95770ed27.Services
@using sv_c4beb1b25b3c466b89242fc95770ed27.Components.Board
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">@errorMessage</div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn Title="To Do"
                     Tasks="@(GetTasksForStatus("To Do"))"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveRight="@(id => MoveTask(id, "In Progress"))"
                     OnAddTask="@(model => AddTask(model, "To Do"))" />

        <BoardColumn Title="In Progress"
                     Tasks="@(GetTasksForStatus("In Progress"))"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveLeft="@(id => MoveTask(id, "To Do"))"
                     OnMoveRight="@(id => MoveTask(id, "Done"))"
                     OnAddTask="@(model => AddTask(model, "In Progress"))" />

        <BoardColumn Title="Done"
                     Tasks="@(GetTasksForStatus("Done"))"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveLeft="@(id => MoveTask(id, "In Progress"))"
                     OnAddTask="@(model => AddTask(model, "Done"))" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetTasksForStatus(string status)
    {
        var filtered = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t =>
                t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var index = allTasks.FindIndex(t => t.Id == taskId);
            if (index >= 0)
            {
                allTasks[index] = allTasks[index] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask(NewTaskModel model, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(
                model.Title, model.Assignee, model.Priority, model.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

